import datetime

def compute_credit(monthly_fee: float, uptime_pct: float) -> float:
    """Return service credit based on negotiated graduated structure."""
    if uptime_pct >= 99.9:
        return 0.0
    elif uptime_pct >= 99.5:
        return monthly_fee * 0.10
    elif uptime_pct >= 99.0:
        return monthly_fee * 0.25
    elif uptime_pct >= 95.0:
        return monthly_fee * 0.50
    else:
        return monthly_fee * 1.00  # full month credit; also triggers termination right

def downtime_minutes(uptime_pct: float, period_hours: int = 24 * 30) -> float:
    return (1 - uptime_pct / 100) * period_hours * 60

monthly_fee = 50_000  # USD

examples = [
    ("99.95% (above SLA)", 99.95),
    ("99.80% (minor breach)", 99.80),
    ("99.30% (moderate breach)", 99.30),
    ("98.00% (major breach)", 98.00),
]

for label, pct in examples:
    credit = compute_credit(monthly_fee, pct)
    downtime = downtime_minutes(pct)
    print(f"{label}: credit=${credit:,.0f} ({credit/monthly_fee:.0%}), downtime={downtime:.0f}min/month")
